ray-project/ray#59150.body:
Use case: two independent deployments of 16 replicas, on a Ray cluster of four nodes, 8GPU per node, 1GPU/replica
- We would like to programmatically fill nodes with replicas of the same deployment
- The result would be that each deployment's replicas spans exactly two nodes
- This is required for independent data parallel groups

The current workaround requires starting workers with custom resources, and enforcing the requirement via `ray_actor_options`:
```
 model_loading_config = ModelLoadingConfig(
      model_id="deepseek",
      model_source="deepseek-ai/DeepSeek-V2-Lite",
  )
  base_engine_kwargs = {
      "tensor_parallel_size": 1,
      "enable_expert_parallel": True,
      "load_format": "dummy",
      "max_model_len": 512,
      "max_num_batched_tokens": 256,
      "enforce_eager": True,
  }

  prefill_config = LLMConfig(
      model_loading_config=model_loading_config,
      engine_kwargs={
          **base_engine_kwargs,
          "data_parallel_size": 4,
          "kv_transfer_config": {
              "kv_connector": "NixlConnector",
              "kv_role": "kv_both",
          },
      },
      experimental_configs={
          "dp_size_per_node": 4,
      },
      runtime_env={"env_vars": {"VLLM_DISABLE_COMPILE_CACHE": "1"}},
      ray_actor_options={"resources": {"prefill": 1}},
  )

  decode_config = LLMConfig(
      model_loading_config=model_loading_config,
      engine_kwargs={
          **base_engine_kwargs,
          "data_parallel_size": 4,
          "kv_transfer_config": {
              "kv_connector": "NixlConnector",
              "kv_role": "kv_both",
          },
      },
      experimental_configs={
          "dp_size_per_node": 4,
      },
      runtime_env={"env_vars": {"VLLM_DISABLE_COMPILE_CACHE": "1"}},
      ray_actor_options={"resources": {"decode": 1}},
  )

  # build_pd_openai_app auto-detects DP and uses build_dp_deployment
  app = build_pd_openai_app(
      {
          "prefill_config": prefill_config,
          "decode_config": decode_config,
      }
  )
  serve.run(app, blocking=False)
```

